--
-- Table structure for table `owners`
--

DROP TABLE IF EXISTS `owners`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `owners` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `tenant_id` int unsigned NOT NULL,
  `site_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `property_owners` text COLLATE utf8mb4_unicode_ci,
  `owners_details` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `paid_status` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `deposit` decimal(10,2) DEFAULT NULL,
  `gst_charges` decimal(10,2) NOT NULL,
  `maintenance_charges` decimal(10,2) DEFAULT NULL,
  `online_paid` decimal(10,2) DEFAULT NULL,
  `cash_paid` decimal(10,2) DEFAULT NULL,
  `muncipal_tax` decimal(10,2) DEFAULT NULL,
  `cma_charges` decimal(10,2) DEFAULT NULL,
  `status` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `payment_date` date DEFAULT NULL,
  `payment_day` tinyint NOT NULL,
  `pending_amount` decimal(10,2) NOT NULL,
  `added_account_no` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `added_bank_name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `added_ifsc` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `manage_by` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `rent_type` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `owner_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `owner_details` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `owner_account_no` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `owner_bank_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `owner_bank_ifsc` varchar(250) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `owner_monthly_rent` decimal(10,2) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_tenant_id` (`tenant_id`),
  KEY `idx_payment_date` (`payment_date`),
  CONSTRAINT `fk_tenant_new` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `owners_ibfk_1` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
);
/*!40101 SET character_set_client = @saved_cs_client */;

