DROP TABLE IF EXISTS `rent_transactions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `rent_transactions` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tenant_id` int unsigned NOT NULL,
  `month_year` date NOT NULL,
  `monthly_rent` decimal(10,2) DEFAULT NULL,
  `payment_type` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `paid_status` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `payment_date` date DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `owner_name` varchar(100) COLLATE utf8mb4_general_ci NOT NULL,
  `payment_amount` int NOT NULL,
  PRIMARY KEY (`id`),
  KEY `rent_transactions_ibfk_1` (`tenant_id`),
  CONSTRAINT `rent_transactions_ibfk_1` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
);
