DROP TABLE IF EXISTS `tenants`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tenants` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `code` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `site_name` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `property_type` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `property_location` text COLLATE utf8mb4_general_ci,
  `property_address` text COLLATE utf8mb4_general_ci,
  `pincode` varchar(10) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `property_owners` text COLLATE utf8mb4_general_ci,
  `owners_details` varchar(200) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `tenant_name` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `address` text COLLATE utf8mb4_general_ci,
  `mobile_no` varchar(15) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `email` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `monthly_rent` int DEFAULT NULL,
  `paid_status` varchar(100) COLLATE utf8mb4_general_ci NOT NULL,
  `deposit` int DEFAULT NULL,
  `gst_charges` int NOT NULL,
  `maintenance_charges` int DEFAULT NULL,
  `online_paid` int DEFAULT NULL,
  `cash_paid` int DEFAULT NULL,
  `muncipal_tax` decimal(5,2) DEFAULT NULL,
  `cma_charges` decimal(5,2) DEFAULT NULL,
  `electricity_charges` decimal(10,2) DEFAULT NULL,
  `electricity_provider` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `water_charges` decimal(5,2) DEFAULT NULL,
  `bank_no` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `bank_name` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `bank_ifsc` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `bank_details` varchar(100) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `agreement_date` date DEFAULT NULL,
  `agreement_expiring` date DEFAULT NULL,
  `fitout_time` date DEFAULT NULL,
  `rent_start_date` date DEFAULT NULL,
  `increased_rent` decimal(10,2) DEFAULT NULL,
  `agreement_years` tinyint unsigned DEFAULT NULL,
  `yearly_escalation_percentage` decimal(5,2) DEFAULT NULL,
  `modified` varchar(100) COLLATE utf8mb4_general_ci NOT NULL,
  `addedby` varchar(100) COLLATE utf8mb4_general_ci NOT NULL,
  `total_amount` decimal(10,2) NOT NULL,
  `status` varchar(100) COLLATE utf8mb4_general_ci NOT NULL,
  `payment_date` date DEFAULT NULL,
  `agent_details` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `agent_cost` decimal(10,2) DEFAULT NULL,
  `authorised_by` varchar(100) COLLATE utf8mb4_general_ci NOT NULL,
  `payment_day` varchar(100) COLLATE utf8mb4_general_ci NOT NULL,
  `area_size` varchar(100) COLLATE utf8mb4_general_ci NOT NULL,
  `pending_amount` int NOT NULL,
  `electricity_consumerno` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `escalation_percentage` decimal(5,2) DEFAULT NULL,
  `added_account_no` int NOT NULL,
  `added_bank_name` varchar(100) COLLATE utf8mb4_general_ci NOT NULL,
  `added_ifsc` varchar(100) COLLATE utf8mb4_general_ci NOT NULL,
  `mseb_deposit` decimal(10,2) DEFAULT NULL,
  `manage_by` varchar(100) COLLATE utf8mb4_general_ci NOT NULL,
  `rent_type` varchar(100) COLLATE utf8mb4_general_ci NOT NULL,
  `authorised_person_commissio` decimal(10,2) DEFAULT NULL,
  `unit` varchar(100) COLLATE utf8mb4_general_ci NOT NULL,
  `consumer_name` varchar(50) COLLATE utf8mb4_general_ci NOT NULL,
  `glocation_link` text COLLATE utf8mb4_general_ci NOT NULL,
  `site_mobileno` text COLLATE utf8mb4_general_ci NOT NULL,
  `website_link` text COLLATE utf8mb4_general_ci NOT NULL,
  `gdrive_link` text COLLATE utf8mb4_general_ci NOT NULL,
  `duplicated` tinyint(1) DEFAULT '0',
  `rent_status` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `electricity_status` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `owner_renttotal` decimal(10,2) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_tenant_name` (`tenant_name`),
  KEY `idx_agreement_expiring` (`agreement_expiring`)
);
/*!40101 SET character_set_client = @saved_cs_client */;

